export interface UserUpdatedEvent {
  type: 'user:updated';
  user: User;
  changes: string[];
  timestamp: Date;
}

export interface NotificationRequestedEvent {
  type: 'notification:requested';
  notification: {
    id: string;
    recipient: string;
    subject: string;
    body: string;
  };
  channel: 'email' | 'sms' | 'webhook' | 'all';
  timestamp: Date;
}

export type AppEvent =
  | OrderCreatedEvent
  | OrderStatusChangedEvent
  | UserCreatedEvent
  | UserUpdatedEvent
  | NotificationRequestedEvent;

